const j = $input.first().json;
const record = (j.body && j.body.record) || j.record || j.body || j;
if (!record) { throw new Error('No record in payload. Expected { record: {...} } or flat body with email/first_name/last_name/attio_deal_id.'); }
const email = record.email;
const firstName = record.first_name || record.firstName || '';
const lastName = record.last_name || record.lastName || '';
const attioDealId = record.attio_deal_id || record.attioDealId || record.deal_id;
if (!email) { throw new Error('email is required to create a FirstPromoter promoter'); }
if (!attioDealId) { throw new Error('attio_deal_id is required so we can write the FirstPromoter code back to the deal'); }
return [{
  json: {
    email,
    first_name: firstName,
    last_name: lastName,
    attio_deal_id: attioDealId,
    cust_id: record.cust_id || record.attio_person_id || email
  }
}];

const j = $input.first().json;
const attioDealId = $('Format Input').item.json.attio_deal_id;
// FirstPromoter response: promotions[0].promo_code is the human-readable affiliate code (the one used on URLs like ?fpr=KEITH).
// Falls back to the API's default_ref_id if promo_code is missing.
const promotions = j.promotions || [];
const code = (promotions[0] && promotions[0].promo_code) || j.default_ref_id || j.cust_id;
if (!code) { throw new Error('No promo_code returned by FirstPromoter. Response: ' + JSON.stringify(j).slice(0, 500)); }
return [{ json: { attio_deal_id: attioDealId, firstpromoter_code: code, firstpromoter_promoter_id: j.id || null } }];
